/**
 * 主应用程序
 * 负责应用的初始化和整体协调
 */

// Import mixins - they register on window.ExamSystemAppMixins
import './mixins/stateMixin.js';
import './mixins/bootstrapMixin.js';
import './mixins/lifecycleMixin.js';
import './mixins/navigationMixin.js';
import './mixins/fallbackMixin.js';

// Import overviewStats - registers on window.AppServices.overviewStats
import '../services/overviewStats.js';

class ExamSystemApp {
    constructor() {
        this.currentView = 'overview';
        this.components = {};
        this.isInitialized = false;

        // 统一状态管理 - 替代全局变量
        this.state = {
            // 考试相关状态
            exam: {
                index: [],
                currentCategory: 'all',
                currentExamType: 'all',
                filteredExams: [],
                configurations: {},
                activeConfigKey: 'exam_index'
            },

            // 练习相关状态
            practice: {
                records: [],
                selectedRecords: new Set(),
                bulkDeleteMode: false,
                dataCollector: null
            },

            // UI状态
            ui: {
                browseFilter: { category: 'all', type: 'all' },
                pendingBrowseFilter: null,
                legacyBrowseType: 'all',
                currentVirtualScroller: null,
                loading: false,
                loadingMessage: ''
            },

            // 组件实例
            components: {
                pdfHandler: null,
                browseStateManager: null,
                practiceListScroller: null
            },

            // 系统状态
            system: {
                processedSessions: new Set(),
                fallbackExamSessions: new Map(),
                failedScripts: new Set()
            }
        };

        // 绑定方法上下文
        this.handleResize = this.handleResize.bind(this);
    }

}

function applyMixins() {
    const mixins = window.ExamSystemAppMixins || {};
    Object.assign(ExamSystemApp.prototype,
        mixins.state || {},
        mixins.bootstrap || {},
        mixins.lifecycle || {},
        mixins.navigation || {},
        mixins.readingLaunch || {},
        mixins.listeningLaunch || {},
        mixins.examSession || {},
        mixins.fallback || {});
}

applyMixins();

window.ExamSystemAppMixins = window.ExamSystemAppMixins || {};
window.ExamSystemAppMixins.__applyToApp = applyMixins;


// 新增修复3E：在js/app.js的DOMContentLoaded初始化中去除顶层await
// 应用启动
document.addEventListener('DOMContentLoaded', () => {
    const signalAppCoreReady = () => {
        try {
            window.dispatchEvent(new CustomEvent('appCoreReady'));
        } catch (_) { }
    };

    const startApp = () => {
        try {
            const mixinGlue = window.ExamSystemAppMixins && window.ExamSystemAppMixins.__applyToApp;
            if (typeof mixinGlue === 'function') {
                mixinGlue();
            }
            (function () {
                try {
                    window.app = new ExamSystemApp();
                    Promise.resolve(window.app.initialize())
                        .catch((error) => {
                            console.error('[App] 初始化失败:', error);
                        })
                        .finally(() => {
                            signalAppCoreReady();
                        });
                } catch (e) {
                    console.error('[App] 初始化失败:', e);
                    signalAppCoreReady();
                }
            })();
        } catch (error) {
            console.error('Failed to start application:', error);
            if (window.handleError) {
                window.handleError(error, 'Application Startup');
            } else {
                // Fallback: non-blocking user message if error handler is unavailable
                try {
                    const container = document.getElementById('message-container');
                    if (container) {
                        const msg = document.createElement('div');
                        msg.className = 'message error';
                        msg.textContent = '系统启动失败，请检查控制台日志。';
                        container.appendChild(msg);
                    }
                } catch (_) {
                    // no-op
                }
            }
            signalAppCoreReady();
        }
    };

    startApp();
});

// 页面卸载时清理
window.addEventListener('beforeunload', () => {
    if (window.app) {
        window.app.destroy();
    }
});

export { ExamSystemApp, applyMixins };
